const dayOfWeek = new Date().getDay();
const postTypes = { 1: 'pain-led', 3: 'value-led', 5: 'offer-led' };
const postType = postTypes[dayOfWeek] || 'value-led';
return [{ json: { postType, date: new Date().toISOString().split('T')[0] } }];

const postType = $('Determine Post Type').first().json.postType;
const recentRows = $input.first().json;
let recentHooks = [];
if (Array.isArray(recentRows)) {
  recentRows.forEach(r => {
    if (r.instagram_hook_text) recentHooks.push(r.instagram_hook_text);
    if (Array.isArray(r.hooks_used)) recentHooks.push(...r.hooks_used);
  });
}
recentHooks = [...new Set(recentHooks)];
return [{ json: { postType, recentHooks: recentHooks.join(', ') || 'none' } }];

const response = $input.first().json;
const content = response.content?.[0]?.text;
if (!content) throw new Error('No content in Claude response: ' + JSON.stringify(response).substring(0, 500));

let parsed;
try {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude response: ' + e.message + '\nRaw: ' + content.substring(0, 500));
}

return [{
  json: {
    ...parsed,
    post_type: $('Determine Post Type').first().json.postType,
    status: 'pending_approval'
  }
}];

